import { BackupItem } from '@eclipse-che/common';
import { PageSection, PageSectionVariants } from '@patternfly/react-core';
import { ICell, sortable, SortByDirection } from '@patternfly/react-table';
import React from 'react';

import { BackupsTable } from '@/pages/WorkspacesList/BackupsView/BackupsTable';
import { buildBackupRows } from '@/pages/WorkspacesList/BackupsView/BackupsTableView/buildRows';
import BackupsListToolbar from '@/pages/WorkspacesList/BackupsView/Toolbar';
import { buildRestoreFromBackupLocation } from '@/services/helpers/location';

const COLUMNS: (ICell | string)[] = [
  { title: 'Workspace Name', dataLabel: 'Workspace Name', transforms: [sortable] },
  { title: 'Backup Time', dataLabel: 'Backup Time', transforms: [sortable] },
  { title: 'Size', dataLabel: 'Size', transforms: [sortable] },
  { title: 'Status', dataLabel: 'Status' },
  { title: '', dataLabel: 'Actions' },
];

type Props = {
  backups: BackupItem[];
  namespace: string;
  navigate: (location: ReturnType<typeof buildRestoreFromBackupLocation>) => void;
  backupSchedule: string | undefined;
};

type State = {
  filterValue: string;
  appliedFilter: string;
  sortBy: { index: number; direction: SortByDirection };
  expandedDropdowns: Record<string, boolean>;
};

export class BackupsTableView extends React.PureComponent<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      filterValue: '',
      appliedFilter: '',
      sortBy: { index: 1, direction: SortByDirection.desc },
      expandedDropdowns: {},
    };
  }

  private handleFilterChange(value: string): void {
    this.setState({ filterValue: value });
  }

  private handleFilterApply(): void {
    this.setState(prevState => ({ appliedFilter: prevState.filterValue }));
  }

  private handleFilterClear(): void {
    this.setState({ filterValue: '', appliedFilter: '' });
  }

  private handleSort(_event: React.MouseEvent, index: number, direction: SortByDirection): void {
    this.setState({ sortBy: { index, direction } });
  }

  private handleDropdownToggle(imageUrl: string, isOpen: boolean): void {
    this.setState(prevState => ({
      expandedDropdowns: { ...prevState.expandedDropdowns, [imageUrl]: isOpen },
    }));
  }

  private handleCreateFromBackup(backup: BackupItem): void {
    this.props.navigate(buildRestoreFromBackupLocation(backup.imageUrl));
  }

  private handleRestoreFromBackup(): void {
    this.props.navigate(buildRestoreFromBackupLocation());
  }

  private getFilteredBackups(): BackupItem[] {
    const { backups } = this.props;
    const { appliedFilter } = this.state;
    if (!appliedFilter) {
      return backups;
    }
    const lowerFilter = appliedFilter.toLowerCase();
    return backups.filter(backup => backup.workspaceName.toLowerCase().includes(lowerFilter));
  }

  private getSortedBackups(backups: BackupItem[]): BackupItem[] {
    const { sortBy } = this.state;
    const sorted = [...backups];
    sorted.sort((a, b) => {
      let comparison = 0;
      switch (sortBy.index) {
        case 0:
          comparison = a.workspaceName.localeCompare(b.workspaceName);
          break;
        case 1: {
          const getTime = (ts: string): number => {
            if (!ts) return 0;
            const t = new Date(ts).getTime();
            return isNaN(t) ? 0 : t;
          };
          comparison = getTime(a.timestamp) - getTime(b.timestamp);
          break;
        }
        case 2:
          comparison = a.sizeBytes - b.sizeBytes;
          break;
        default:
          comparison = 0;
      }
      return sortBy.direction === SortByDirection.asc ? comparison : -comparison;
    });
    return sorted;
  }

  public render(): React.ReactElement {
    const { backups, namespace, backupSchedule } = this.props;
    const { sortBy, filterValue, expandedDropdowns } = this.state;

    const filtered = this.getFilteredBackups();
    const sorted = this.getSortedBackups(filtered);
    const rows = buildBackupRows(
      sorted,
      namespace,
      expandedDropdowns,
      (imageUrl, isOpen) => this.handleDropdownToggle(imageUrl, isOpen),
      backup => this.handleCreateFromBackup(backup),
    );

    const toolbar = (
      <BackupsListToolbar
        filterValue={filterValue}
        backupSchedule={backupSchedule}
        onFilterChange={value => this.handleFilterChange(value)}
        onFilterApply={() => this.handleFilterApply()}
        onFilterClear={() => this.handleFilterClear()}
        onRestoreClick={() => this.handleRestoreFromBackup()}
      />
    );

    return (
      <>
        <BackupsTable
          columns={COLUMNS}
          rows={rows}
          sortBy={sortBy}
          onSort={(event, index, direction) => this.handleSort(event, index, direction)}
          toolbar={toolbar}
        />
        {rows.length === 0 && backups.length > 0 && (
          <PageSection variant={PageSectionVariants.light} isFilled={true}>
            <span data-testid="backups-nothing-found">No backups match the filter criteria.</span>
          </PageSection>
        )}
      </>
    );
  }
}
